import{_ as o,o as s,c as t,a2 as a}from"./chunks/framework.jisAoZJG.js";const h=JSON.parse('{"title":"@sqlrooms/blocks","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/api/documents/_media/README.html"}]]},"headers":[],"relativePath":"api/documents/_media/README.md","filePath":"api/documents/_media/README.md"}'),c={name:"api/documents/_media/README.md"};function n(r,e,l,i,d,m){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="sqlrooms-blocks" tabindex="-1">@sqlrooms/blocks <a class="header-anchor" href="#sqlrooms-blocks" aria-label="Permalink to &quot;@sqlrooms/blocks&quot;">​</a></h1><p>Shared contracts and vocabulary for composable SQLRooms blocks.</p><p>Blocks are reusable units of SQLRooms workspace state or behavior. A block can be small and local, like a text or chart block, or stateful, like a dashboard, pivot table, notebook, or app surface. This package defines the shared language for those block-shaped resources without owning their concrete runtime.</p><p>This package intentionally contains no feature runtime, stores, or UI implementations. Feature packages own concrete block definitions:</p><ul><li><code>@sqlrooms/mosaic</code> owns dashboard/chart block implementations.</li><li><code>@sqlrooms/pivot</code> owns pivot block implementations.</li><li><code>@sqlrooms/documents</code> owns document and rich content block implementations.</li><li>Notebook/canvas/app packages own their own stateful block implementations.</li></ul><p><code>@sqlrooms/blocks</code> provides the small shared contract layer that lets those implementations be hosted consistently in artifacts, documents, notebooks, or other block containers.</p><h2 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h2><ul><li><code>BlockInstance</code> identifies a block and stores portable block attributes.</li><li><code>BlockReference</code> points at state managed elsewhere and records whether that state is owned, shared, or external.</li><li><code>StatefulBlockDefinition</code> describes how a feature package creates, ensures, renames, deletes, closes, and renders its block state.</li><li><code>OrderedBlockContainer</code> and <code>GraphBlockContainer</code> describe common container shapes: linear documents and DAG-like notebooks.</li></ul><p>Concrete packages should keep their own state slices and renderers close to their domain. For example, dashboard blocks remain owned by <code>@sqlrooms/mosaic</code>, pivot blocks remain owned by <code>@sqlrooms/pivot</code>, and Markdown document blocks remain owned by <code>@sqlrooms/documents</code>.</p><h2 id="block-documents" tabindex="-1">Block Documents <a class="header-anchor" href="#block-documents" aria-label="Permalink to &quot;Block Documents&quot;">​</a></h2><p>The first rich ordered block container in SQLRooms is <a href="./../documents/README.html#block-documents"><code>BlockDocument</code></a> from <code>@sqlrooms/documents</code>. <code>BlockDocument</code> uses these shared contracts to host text, images, charts, and stateful blocks while keeping the editor/document runtime in the documents package.</p><p>Use <code>@sqlrooms/blocks</code> when defining cross-package contracts for block-shaped resources. Use <code>@sqlrooms/documents</code> when you need the Tiptap-backed <code>BlockDocument</code> editor, persistence slice, commands, or AI authoring tools.</p>',12)])])}const k=o(c,[["render",n]]);export{h as __pageData,k as default};
